import{_ as t,o as a,c as l,ag as r}from"./chunks/framework.eQLvDOR_.js";const m=JSON.parse('{"title":"augmented-llm","description":"","frontmatter":{"title":"augmented-llm","concept":"Augmented LLM","concept_id":"augmented-llm","aliases":["增强型 LLM","Atomic-Agent-Block"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Building Effective AI Agents.md"],"related_concepts":["[[agent-computer-interface]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/augmented-llm.md","filePath":"wiki/concepts/augmented-llm.md","lastUpdated":null}'),o={name:"wiki/concepts/augmented-llm.md"};function n(i,e,s,c,d,g){return a(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="augmented-llm-增强型-llm" tabindex="-1">Augmented LLM (增强型 LLM) <a class="header-anchor" href="#augmented-llm-增强型-llm" aria-label="Permalink to &quot;Augmented LLM (增强型 LLM)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>Agentic Systems 的基本构建块，是标准 LLM 加上各种<strong>增强能力 (Augmentations)</strong> 的组合。</p><h2 id="核心增强维度" tabindex="-1">核心增强维度 <a class="header-anchor" href="#核心增强维度" aria-label="Permalink to &quot;核心增强维度&quot;">​</a></h2><ol><li><strong>Retrieval (检索)</strong>：访问外部知识库 (RAG)。</li><li><strong>Tools (工具使用)</strong>：执行外部代码、调用 API。</li><li><strong>Memory (记忆)</strong>：在长会话中保留关键信息。</li></ol><h2 id="构建原则" tabindex="-1">构建原则 <a class="header-anchor" href="#构建原则" aria-label="Permalink to &quot;构建原则&quot;">​</a></h2><ul><li><strong>定制化</strong>：根据具体用例定制能力的边界。</li><li><strong>接口一致性</strong>：为 LLM 提供易于理解、文档齐全的接口。</li><li><strong>标准化</strong>：推荐使用 <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol (MCP)</a> 来统一工具集成。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>MCP 优先原则</strong>：优先寻找现成的 MCP Server (如 Google Maps, GitHub, SQLite)，避免为通用功能手写单独工具。</li><li><strong>记忆策展 (Memory Curation)</strong>：不要存储每一轮对话。仅在检测到明显的“设置、偏好、结论”时，手动触发核心事实存储任务。</li><li><strong>环境隔离</strong>：在生产环境中，Tools 增强应运行在 Docker 或沙箱化 shell 中，严禁 Agent 直接访问敏感环境变量。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Building Effective AI Agents.html">[Agent_Architecture] Building Effective AI Agents</a></li></ul>',13)])])}const h=t(o,[["render",n]]);export{m as __pageData,h as default};
